# Comprehensive audit of all 3 customers
customer_ids = ['CUST-8842', 'CUST-2244', 'CUST-5501']

# Step 1: Get all customer profiles
profiles = {}
for cid in customer_ids:
    profiles[cid] = tool('get_customer', customer_id=cid)

# Step 2: Get order history for all customers
order_histories = {}
for cid in customer_ids:
    order_histories[cid] = tool('get_order_history', customer_id=cid)

# Step 3: Collect all non-returned orders and look up their details
all_orders_detail = {}
all_skus = []

for cid in customer_ids:
    orders = order_histories[cid]['orders']
    non_returned = [o for o in orders if o['status'] != 'returned']

    for order in non_returned:
        order_detail = tool('lookup_order', order_id=order['id'])
        all_orders_detail[order['id']] = order_detail

        # Collect all SKUs from this order
        for item in order_detail['items']:
            all_skus.append(item['sku'])

# Step 4: Check inventory for all SKUs
unique_skus = []
seen = set()
for sku in all_skus:
    if sku not in seen:
        unique_skus.append(sku)
        seen.add(sku)

inventory_check = tool('check_inventory', sku_list=unique_skus)

# Step 5: Build audit results per customer
audit_results = {}

for cid in customer_ids:
    customer = profiles[cid]
    orders = order_histories[cid]['orders']
    non_returned_orders = [o for o in orders if o['status'] != 'returned']

    # Collect order details and inventory issues for this customer
    customer_orders_detail = []
    out_of_stock_items = []

    for order in non_returned_orders:
        order_detail = all_orders_detail[order['id']]
        order_info = {
            'order_id': order['id'],
            'date': order['date'],
            'status': order['status'],
            'total': order['total'],
            'items': []
        }

        for item in order_detail['items']:
            item_info = {
                'name': item['name'],
                'sku': item['sku'],
                'price': item['price']
            }

            # Check inventory for this SKU
            inv_item = [i for i in inventory_check['items'] if i['sku'] == item['sku']]
            if inv_item:
                inv = inv_item[0]
                item_info['available'] = inv['available']
                item_info['warehouse'] = inv['warehouse']

                if inv['available'] == 0:
                    out_of_stock_items.append({
                        'order_id': order['id'],
                        'item_name': item['name'],
                        'sku': item['sku'],
                        'warehouse': inv['warehouse'],
                        'restock_date': inv.get('restock_date', 'Unknown')
                    })

            order_info['items'].append(item_info)

        customer_orders_detail.append(order_info)

    audit_results[cid] = {
        'customer': customer,
        'total_orders': len(orders),
        'non_returned_orders': len(non_returned_orders),
        'returned_orders': len(orders) - len(non_returned_orders),
        'orders_detail': customer_orders_detail,
        'out_of_stock_items': out_of_stock_items,
        'total_value_non_returned': sum(o['total'] for o in non_returned_orders)
    }

# Step 6: Send summary emails to each customer
email_results = []

for cid in customer_ids:
    audit = audit_results[cid]
    customer = audit['customer']

    # Build email body
    body = f"""Dear {customer['name']},

CUSTOMER AUDIT SUMMARY (as of 2026-03-10)

Account Information:
- Customer ID: {cid}
- Email: {customer['email']}
- Membership Tier: {customer['tier']}
- Loyalty Points: {customer['loyalty_points']}
- Account Status: {customer['account_status']}
- Member Since: {customer['member_since']}

Order Summary:
- Total Orders: {audit['total_orders']}
- Non-Returned Orders: {audit['non_returned_orders']}
- Returned Orders: {audit['returned_orders']}
- Total Value (Non-Returned): ${audit['total_value_non_returned']:.2f}

Order Details:
"""

    for order in audit['orders_detail']:
        body += f"\nOrder {order['order_id']} ({order['date']}) - Status: {order['status']} - Total: ${order['total']:.2f}\n"
        for item in order['items']:
            body += f"  • {item['name']} (SKU: {item['sku']}) - ${item['price']:.2f}\n"
            body += f"    Available: {item['available']} units (Warehouse: {item['warehouse']})\n"

    # Add out-of-stock alerts
    if audit['out_of_stock_items']:
        body += f"\n⚠️  OUT-OF-STOCK ITEMS ALERT:\n"
        for oos in audit['out_of_stock_items']:
            body += f"- {oos['item_name']} (SKU: {oos['sku']}) in Order {oos['order_id']}\n"
            body += f"  Warehouse: {oos['warehouse']}, Restock Date: {oos['restock_date']}\n"
    else:
        body += f"\n✓ All items in non-returned orders are in stock.\n"

    body += f"\nBest regards,\nAudit Team"

    # Send email
    email_result = tool('send_notification', 
                       channel='email',
                       recipient=customer['email'],
                       subject=f'Customer Audit Summary - {cid}',
                       body=body)

    email_results.append({
        'customer_id': cid,
        'email_sent_to': customer['email'],
        'notification_id': email_result['notification_id'],
        'status': email_result['status']
    })

# Return comprehensive audit summary
{
    'audit_summary': {
        'total_customers_audited': len(customer_ids),
        'customers': list(audit_results.keys()),
        'audit_date': '2026-03-10'
    },
    'customer_audits': {
        cid: {
            'customer_name': audit_results[cid]['customer']['name'],
            'total_orders': audit_results[cid]['total_orders'],
            'non_returned_orders': audit_results[cid]['non_returned_orders'],
            'total_value': audit_results[cid]['total_value_non_returned'],
            'out_of_stock_count': len(audit_results[cid]['out_of_stock_items']),
            'out_of_stock_items': audit_results[cid]['out_of_stock_items']
        }
        for cid in customer_ids
    },
    'emails_sent': email_results
}
